try {
  const task = $input.first().json.body ?? $input.first().json;

  const defaultDatetime = () => {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    d.setHours(9, 0, 0, 0);
    return d.toISOString();
  };

  const addHour = (dt) =>
    new Date(new Date(dt).getTime() + 3600000).toISOString();

  const detectCategory = (text) => {
    if (!text) return 'כללי';
    const work     = ['לקוח','פגישה','עבודה','מייל','פרויקט','דוח','ישיבה','זום'];
    const personal = ['לקנות','בית','משפחה','ילדים','אוכל','רופא','קניות'];
    if (work.some(k => text.includes(k)))     return 'מקצועי';
    if (personal.some(k => text.includes(k))) return 'אישי';
    return 'כללי';
  };

  const datetime = task.datetime || defaultDatetime();

  const out = {
    text:        task.text     || '',
    category:    task.category || detectCategory(task.text),
    datetime,
    endDatetime: addHour(datetime),
    createdAt:   task.createdAt || new Date().toISOString(),
    completed:   task.completed || false,
    email:       task.email    || ''
  };

  return [{ json: out }];

} catch (err) {
  throw new Error('שגיאה בעיבוד נתונים: ' + err.message);
}
